3128     /// Data structure that helps to reorder operands.
3129     struct OperandsOrderData {
3130       /// The best number of operands with the same APOs, which can be
3131       /// reordered.
3132       unsigned NumOfAPOs = UINT_MAX;
3133       /// Number of operands with the same/alternate instruction opcode and
3134       /// parent.
3135       unsigned NumOpsWithSameOpcodeParent = 0;
3136       /// Hash for the actual operands ordering.
3137       /// Used to count operands, actually their position id and opcode
3138       /// value. It is used in the voting mechanism to find the lane with the
3139       /// least number of operands that can freely move about or less profitable
3140       /// because it already has the most optimal set of operands. Can be
3141       /// replaced with SmallVector<unsigned> instead but hash code is faster
3142       /// and requires less memory.
3143       unsigned Hash = 0;
