2632     /// Go through the operands of \p LHS and \p RHS recursively until
2633     /// MaxLevel, and return the cummulative score. \p U1 and \p U2 are
2634     /// the users of \p LHS and \p RHS (that is \p LHS and \p RHS are operands
2635     /// of \p U1 and \p U2), except at the beginning of the recursion where
2636     /// these are set to nullptr.
2637     ///
2638     /// For example:
2639     /// \verbatim
2640     ///  A[0]  B[0]  A[1]  B[1]  C[0] D[0]  B[1] A[1]
2641     ///     \ /         \ /         \ /        \ /
2642     ///      +           +           +          +
2643     ///     G1          G2          G3         G4
2644     /// \endverbatim
2645     /// The getScoreAtLevelRec(G1, G2) function will try to match the nodes at
2646     /// each level recursively, accumulating the score. It starts from matching
2647     /// the additions at level 0, then moves on to the loads (level 1). The
2648     /// score of G1 and G2 is higher than G1 and G3, because {A[0],A[1]} and
2649     /// {B[0],B[1]} match with LookAheadHeuristics::ScoreConsecutiveLoads, while
2650     /// {A[0],C[0]} has a score of LookAheadHeuristics::ScoreFail.
2651     /// Please note that the order of the operands does not matter, as we
2652     /// evaluate the score of all profitable combinations of operands. In
2653     /// other words the score of G1 and G4 is the same as G1 and G2. This
2654     /// heuristic is based on ideas described in:
2655     ///   Look-ahead SLP: Auto-vectorization in the presence of commutative
2656     ///   operations, CGO 2018 by Vasileios Porpodas, Rodrigo C. O. Rocha,
2657     ///   Luís F. W. Góes
2658     int getScoreAtLevelRec(Value *LHS, Value *RHS, Instruction *U1,
2659                            Instruction *U2, int CurrLevel,
2660                            ArrayRef<Value *> MainAltOps) const {
2661 
2662       // Get the shallow score of V1 and V2.
2663       int ShallowScoreAtThisLevel =
2664           getShallowScore(LHS, RHS, U1, U2, MainAltOps);
2665 
2666       // If reached MaxLevel,
2667       //  or if V1 and V2 are not instructions,
2668       //  or if they are SPLAT,
2669       //  or if they are not consecutive,
2670       //  or if profitable to vectorize loads or extractelements, early return
2671       //  the current cost.
2672       auto *I1 = dyn_cast<Instruction>(LHS);
2673       auto *I2 = dyn_cast<Instruction>(RHS);
2674       if (CurrLevel == MaxLevel || !(I1 && I2) || I1 == I2 ||
2675           ShallowScoreAtThisLevel == LookAheadHeuristics::ScoreFail ||
2676           (((isa<LoadInst>(I1) && isa<LoadInst>(I2)) ||
2677             (I1->getNumOperands() > 2 && I2->getNumOperands() > 2) ||
2678             (isa<ExtractElementInst>(I1) && isa<ExtractElementInst>(I2))) &&
2679            ShallowScoreAtThisLevel))
2680         return ShallowScoreAtThisLevel;
2681       assert(I1 && I2 && "Should have early exited.");
2682 
2683       // Contains the I2 operand indexes that got matched with I1 operands.
2684       SmallSet<unsigned, 4> Op2Used;
2685 
2686       // Recursion towards the operands of I1 and I2. We are trying all possible
2687       // operand pairs, and keeping track of the best score.
2688       if (I1->getNumOperands() != I2->getNumOperands())
2689         return LookAheadHeuristics::ScoreSameOpcode;
2690       for (unsigned OpIdx1 = 0, NumOperands1 = I1->getNumOperands();
2691            OpIdx1 != NumOperands1; ++OpIdx1) {
2692         // Try to pair op1I with the best operand of I2.
2693         int MaxTmpScore = 0;
2694         unsigned MaxOpIdx2 = 0;
2695         bool FoundBest = false;
2696         // If I2 is commutative try all combinations.
2697         unsigned FromIdx = isCommutative(I2) ? 0 : OpIdx1;
2698         unsigned ToIdx = isCommutative(I2)
2699                              ? I2->getNumOperands()
2700                              : std::min(I2->getNumOperands(), OpIdx1 + 1);
2701         assert(FromIdx <= ToIdx && "Bad index");
2702         for (unsigned OpIdx2 = FromIdx; OpIdx2 != ToIdx; ++OpIdx2) {
2703           // Skip operands already paired with OpIdx1.
2704           if (Op2Used.count(OpIdx2))
2705             continue;
2706           // Recursively calculate the cost at each level
2707           int TmpScore =
2708               getScoreAtLevelRec(I1->getOperand(OpIdx1), I2->getOperand(OpIdx2),
2709                                  I1, I2, CurrLevel + 1, {});
2710           // Look for the best score.
2711           if (TmpScore > LookAheadHeuristics::ScoreFail &&
2712               TmpScore > MaxTmpScore) {
2713             MaxTmpScore = TmpScore;
2714             MaxOpIdx2 = OpIdx2;
2715             FoundBest = true;
2716           }
2717         }
2718         if (FoundBest) {
2719           // Pair {OpIdx1, MaxOpIdx2} was found to be best. Never revisit it.
2720           Op2Used.insert(MaxOpIdx2);
2721           ShallowScoreAtThisLevel += MaxTmpScore;
2722         }
2723       }
2724       return ShallowScoreAtThisLevel;
2725     }
