3627         if (auto *OpI = dyn_cast_if_present<Instruction>(U.get());
3628             OpI && !DeletedInstructions.contains(OpI) && OpI->hasOneUser() &&
3629             wouldInstructionBeTriviallyDead(OpI, TLI) &&
3630             (Entries.empty() || none_of(Entries, [&](const TreeEntry *Entry) {
3631                return Entry->VectorizedValue == OpI;
3632              })))
3633           DeadInsts.push_back(OpI);
3634       }
3635       I->dropAllReferences();
3636     }
3637     for (T *V : DeadVals) {
3638       auto *I = cast<Instruction>(V);
3639       if (!I->getParent())
3640         continue;
3641       assert((I->use_empty() || all_of(I->uses(),
3642                                        [&](Use &U) {
3643                                          return isDeleted(
3644                                              cast<Instruction>(U.getUser()));
3645                                        })) &&
3646              "trying to erase instruction with users.");
3647       I->removeFromParent();
3648       SE->forgetValue(I);
3649     }
3650     // Process the dead instruction list until empty.
3651     while (!DeadInsts.empty()) {
3652       Value *V = DeadInsts.pop_back_val();
3653       Instruction *VI = cast_or_null<Instruction>(V);
3654       if (!VI || !VI->getParent())
3655         continue;
3656       assert(isInstructionTriviallyDead(VI, TLI) &&
