3679               (!OpI->getType()->isVectorTy() ||
3680                none_of(VectorValuesAndScales,
3681                        [&](const std::tuple<Value *, unsigned, bool, bool> &V) {
3682                          return std::get<0>(V) == OpI;
3683                        })) &&
3684               isInstructionTriviallyDead(OpI, TLI))
3685             DeadInsts.push_back(OpI);
3686       }
3687 
3688       VI->removeFromParent();
3689       eraseInstruction(VI);
3690       SE->forgetValue(VI);
