1792 /// Order may have elements assigned special value (size) which is out of
1793 /// bounds. Such indices only appear on places which correspond to undef values
1794 /// (see canReuseExtract for details) and used in order to avoid undef values
1795 /// have effect on operands ordering.
1796 /// The first loop below simply finds all unused indices and then the next loop
1797 /// nest assigns these indices for undef values positions.
1798 /// As an example below Order has two undef positions and they have assigned
1799 /// values 3 and 7 respectively:
1800 /// before:  6 9 5 4 9 2 1 0
1801 /// after:   6 3 5 4 7 2 1 0
1802 static void fixupOrderingIndices(MutableArrayRef<unsigned> Order) {
1803   const size_t Sz = Order.size();
1804   SmallBitVector UnusedIndices(Sz, /*t=*/true);
1805   SmallBitVector MaskedIndices(Sz);
1806   for (unsigned I = 0; I < Sz; ++I) {
1807     if (Order[I] < Sz)
1808       UnusedIndices.reset(Order[I]);
1809     else
1810       MaskedIndices.set(I);
1811   }
1812   if (MaskedIndices.none())
1813     return;
1814   assert(UnusedIndices.count() == MaskedIndices.count() &&
1815          "Non-synced masked/available indices.");
1816   int Idx = UnusedIndices.find_first();
1817   int MIdx = MaskedIndices.find_first();
1818   while (MIdx >= 0) {
1819     assert(Idx >= 0 && "Indices must be synced.");
1820     Order[MIdx] = Idx;
1821     Idx = UnusedIndices.find_next(Idx);
1822     MIdx = MaskedIndices.find_next(MIdx);
1823   }
1824 }
