3074     /// Helper for reorderOperandVecs.
3075     /// \returns the lane that we should start reordering from. This is the one
3076     /// which has the least number of operands that can freely move about or
3077     /// less profitable because it already has the most optimal set of operands.
3078     unsigned getBestLaneToStartReordering() const {
3079       unsigned Min = UINT_MAX;
3080       unsigned SameOpNumber = 0;
3081       // std::pair<unsigned, unsigned> is used to implement a simple voting
3082       // algorithm and choose the lane with the least number of operands that
3083       // can freely move about or less profitable because it already has the
3084       // most optimal set of operands. The first unsigned is a counter for
3085       // voting, the second unsigned is the counter of lanes with instructions
3086       // with same/alternate opcodes and same parent basic block.
3087       MapVector<unsigned, std::pair<unsigned, unsigned>> HashMap;
3088       // Try to be closer to the original results, if we have multiple lanes
3089       // with same cost. If 2 lanes have the same cost, use the one with the
3090       // highest index.
3091       for (int I = getNumLanes(); I > 0; --I) {
3092         unsigned Lane = I - 1;
3093         OperandsOrderData NumFreeOpsHash =
3094             getMaxNumOperandsThatCanBeReordered(Lane);
3095         // Compare the number of operands that can move and choose the one with
3096         // the least number.
3097         if (NumFreeOpsHash.NumOfAPOs < Min) {
3098           Min = NumFreeOpsHash.NumOfAPOs;
3099           SameOpNumber = NumFreeOpsHash.NumOpsWithSameOpcodeParent;
3100           HashMap.clear();
3101           HashMap[NumFreeOpsHash.Hash] = std::make_pair(1, Lane);
3102         } else if (NumFreeOpsHash.NumOfAPOs == Min &&
3103                    NumFreeOpsHash.NumOpsWithSameOpcodeParent < SameOpNumber) {
3104           // Select the most optimal lane in terms of number of operands that
3105           // should be moved around.
3106           SameOpNumber = NumFreeOpsHash.NumOpsWithSameOpcodeParent;
3107           HashMap[NumFreeOpsHash.Hash] = std::make_pair(1, Lane);
3108         } else if (NumFreeOpsHash.NumOfAPOs == Min &&
3109                    NumFreeOpsHash.NumOpsWithSameOpcodeParent == SameOpNumber) {
3110           auto [It, Inserted] =
3111               HashMap.try_emplace(NumFreeOpsHash.Hash, 1, Lane);
3112           if (!Inserted)
3113             ++It->second.first;
3114         }
3115       }
3116       // Select the lane with the minimum counter.
3117       unsigned BestLane = 0;
3118       unsigned CntMin = UINT_MAX;
3119       for (const auto &Data : reverse(HashMap)) {
3120         if (Data.second.first < CntMin) {
3121           CntMin = Data.second.first;
3122           BestLane = Data.second.second;
3123         }
3124       }
3125       return BestLane;
3126     }
