3145     /// \returns the maximum number of operands that are allowed to be reordered
3146     /// for \p Lane and the number of compatible instructions(with the same
3147     /// parent/opcode). This is used as a heuristic for selecting the first lane
3148     /// to start operand reordering.
3149     OperandsOrderData getMaxNumOperandsThatCanBeReordered(unsigned Lane) const {
3150       unsigned CntTrue = 0;
3151       unsigned NumOperands = getNumOperands();
3152       // Operands with the same APO can be reordered. We therefore need to count
3153       // how many of them we have for each APO, like this: Cnt[APO] = x.
3154       // Since we only have two APOs, namely true and false, we can avoid using
3155       // a map. Instead we can simply count the number of operands that
3156       // correspond to one of them (in this case the 'true' APO), and calculate
3157       // the other by subtracting it from the total number of operands.
3158       // Operands with the same instruction opcode and parent are more
3159       // profitable since we don't need to move them in many cases, with a high
3160       // probability such lane already can be vectorized effectively.
3161       bool AllUndefs = true;
3162       unsigned NumOpsWithSameOpcodeParent = 0;
3163       Instruction *OpcodeI = nullptr;
3164       BasicBlock *Parent = nullptr;
3165       unsigned Hash = 0;
3166       for (unsigned OpIdx = 0; OpIdx != NumOperands; ++OpIdx) {
3167         const OperandData &OpData = getData(OpIdx, Lane);
3168         if (OpData.APO)
3169           ++CntTrue;
3170         // Use Boyer-Moore majority voting for finding the majority opcode and
3171         // the number of times it occurs.
3172         if (auto *I = dyn_cast<Instruction>(OpData.V)) {
3173           if (!OpcodeI || !getSameOpcode({OpcodeI, I}, TLI) ||
3174               I->getParent() != Parent) {
3175             if (NumOpsWithSameOpcodeParent == 0) {
3176               NumOpsWithSameOpcodeParent = 1;
3177               OpcodeI = I;
3178               Parent = I->getParent();
3179             } else {
3180               --NumOpsWithSameOpcodeParent;
3181             }
3182           } else {
3183             ++NumOpsWithSameOpcodeParent;
3184           }
3185         }
3186         Hash = hash_combine(
3187             Hash, hash_value((OpIdx + 1) * (OpData.V->getValueID() + 1)));
3188         AllUndefs = AllUndefs && isa<UndefValue>(OpData.V);
3189       }
3190       if (AllUndefs)
3191         return {};
3192       OperandsOrderData Data;
3193       Data.NumOfAPOs = std::max(CntTrue, NumOperands - CntTrue);
3194       Data.NumOpsWithSameOpcodeParent = NumOpsWithSameOpcodeParent;
3195       Data.Hash = Hash;
3196       return Data;
3197     }
