3210       // arguments to the intrinsic produces the same result.
3211       Instruction *MainOp = S.getMainOp();
3212       unsigned NumOperands = MainOp->getNumOperands();
3213       ArgSize = ::getNumberOfPotentiallyCommutativeOps(MainOp);
3214       OpsVec.resize(ArgSize);
3215       unsigned NumLanes = VL.size();
3216       for (OperandDataVec &Ops : OpsVec)
3217         Ops.resize(NumLanes);
