3219         // Our tree has just 3 nodes: the root and two operands.
3220         // It is therefore trivial to get the APO. We only need to check the
3221         // opcode of V and whether the operand at OpIdx is the LHS or RHS
3222         // operand. The LHS operand of both add and sub is never attached to an
3223         // inversese operation in the linearized form, therefore its APO is
3224         // false. The RHS is true only if V is an inverse operation.
3225 
3226         // Since operand reordering is performed on groups of commutative
3227         // operations or alternating sequences (e.g., +, -), we can safely tell
3228         // the inverse operations by checking commutativity.
3229         auto *I = dyn_cast<Instruction>(VL[Lane]);
3230         if (!I && isa<PoisonValue>(VL[Lane])) {
3231           for (unsigned OpIdx : seq<unsigned>(NumOperands))
3232             OpsVec[OpIdx][Lane] = {Operands[OpIdx][Lane], true, false};
