3272     /// \Returns true if there are enough operands identical to \p Op to fill
3273     /// the whole vector (it is mixed with constants or loop invariant values).
3274     /// Note: This modifies the 'IsUsed' flag, so a cleanUsed() must follow.
3275     bool shouldBroadcast(Value *Op, unsigned OpIdx, unsigned Lane) {
3276       assert(Op == getValue(OpIdx, Lane) &&
3277              "Op is expected to be getValue(OpIdx, Lane).");
3278       // Small number of loads - try load matching.
3279       if (isa<LoadInst>(Op) && getNumLanes() == 2 && getNumOperands() == 2)
3280         return false;
3281       bool OpAPO = getData(OpIdx, Lane).APO;
3282       bool IsInvariant = L && L->isLoopInvariant(Op);
3283       unsigned Cnt = 0;
3284       for (unsigned Ln = 0, Lns = getNumLanes(); Ln != Lns; ++Ln) {
3285         if (Ln == Lane)
3286           continue;
3287         // This is set to true if we found a candidate for broadcast at Lane.
3288         bool FoundCandidate = false;
3289         for (unsigned OpI = 0, OpE = getNumOperands(); OpI != OpE; ++OpI) {
3290           OperandData &Data = getData(OpI, Ln);
3291           if (Data.APO != OpAPO || Data.IsUsed)
3292             continue;
3293           Value *OpILane = getValue(OpI, Lane);
3294           bool IsConstantOp = isa<Constant>(OpILane);
3295           // Consider the broadcast candidate if:
3296           // 1. Same value is found in one of the operands.
3297           if (Data.V == Op ||
3298               // 2. The operand in the given lane is not constant but there is a
3299               // constant operand in another lane (which can be moved to the
3300               // given lane). In this case we can represent it as a simple
3301               // permutation of constant and broadcast.
3302               (!IsConstantOp &&
3303                ((Lns > 2 && isa<Constant>(Data.V)) ||
3304                 // 2.1. If we have only 2 lanes, need to check that value in the
3305                 // next lane does not build same opcode sequence.
3306                 (Lns == 2 &&
3307                  !getSameOpcode({Op, getValue((OpI + 1) % OpE, Ln)}, TLI) &&
3308                  isa<Constant>(Data.V)))) ||
3309               // 3. The operand in the current lane is loop invariant (can be
3310               // hoisted out) and another operand is also a loop invariant
3311               // (though not a constant). In this case the whole vector can be
3312               // hoisted out.
3313               // FIXME: need to teach the cost model about this case for better
3314               // estimation.
3315               (IsInvariant && !isa<Constant>(Data.V) &&
3316                !getSameOpcode({Op, Data.V}, TLI) &&
3317                L->isLoopInvariant(Data.V))) {
3318             FoundCandidate = true;
3319             Data.IsUsed = Data.V == Op;
3320             if (Data.V == Op)
3321               ++Cnt;
3322             break;
3323           }
3324         }
3325         if (!FoundCandidate)
3326           return false;
3327       }
3328       return getNumLanes() == 2 || Cnt > 1;
3329     }
