3331     /// Checks if there is at least single compatible operand in lanes other
3332     /// than \p Lane, compatible with the operand \p Op.
3333     bool canBeVectorized(Instruction *Op, unsigned OpIdx, unsigned Lane) const {
3334       assert(Op == getValue(OpIdx, Lane) &&
3335              "Op is expected to be getValue(OpIdx, Lane).");
3336       bool OpAPO = getData(OpIdx, Lane).APO;
3337       for (unsigned Ln = 0, Lns = getNumLanes(); Ln != Lns; ++Ln) {
3338         if (Ln == Lane)
3339           continue;
3340         if (any_of(seq<unsigned>(getNumOperands()), [&](unsigned OpI) {
3341               const OperandData &Data = getData(OpI, Ln);
3342               if (Data.APO != OpAPO || Data.IsUsed)
3343                 return true;
3344               Value *OpILn = getValue(OpI, Ln);
3345               return (L && L->isLoopInvariant(OpILn)) ||
3346                      (getSameOpcode({Op, OpILn}, TLI) &&
3347                       allSameBlock({Op, OpILn}));
3348             }))
3349           return true;
3350       }
3351       return false;
3352     }
