3375     // Performs operand reordering for 2 or more operands.
3376     // The original operands are in OrigOps[OpIdx][Lane].
3377     // The reordered operands are returned in 'SortedOps[OpIdx][Lane]'.
3378     void reorder() {
3379       unsigned NumOperands = getNumOperands();
3380       unsigned NumLanes = getNumLanes();
3381       // Each operand has its own mode. We are using this mode to help us select
3382       // the instructions for each lane, so that they match best with the ones
3383       // we have selected so far.
3384       SmallVector<ReorderingMode, 2> ReorderingModes(NumOperands);
3385 
3386       // This is a greedy single-pass algorithm. We are going over each lane
3387       // once and deciding on the best order right away with no back-tracking.
3388       // However, in order to increase its effectiveness, we start with the lane
3389       // that has operands that can move the least. For example, given the
3390       // following lanes:
3391       //  Lane 0 : A[0] = B[0] + C[0]   // Visited 3rd
3392       //  Lane 1 : A[1] = C[1] - B[1]   // Visited 1st
3393       //  Lane 2 : A[2] = B[2] + C[2]   // Visited 2nd
3394       //  Lane 3 : A[3] = C[3] - B[3]   // Visited 4th
3395       // we will start at Lane 1, since the operands of the subtraction cannot
3396       // be reordered. Then we will visit the rest of the lanes in a circular
3397       // fashion. That is, Lanes 2, then Lane 0, and finally Lane 3.
3398 
3399       // Find the first lane that we will start our search from.
3400       unsigned FirstLane = getBestLaneToStartReordering();
3401 
3402       // Initialize the modes.
3403       for (unsigned OpIdx = 0; OpIdx != NumOperands; ++OpIdx) {
3404         Value *OpLane0 = getValue(OpIdx, FirstLane);
3405         // Keep track if we have instructions with all the same opcode on one
3406         // side.
3407         if (auto *OpILane0 = dyn_cast<Instruction>(OpLane0)) {
3408           // Check if OpLane0 should be broadcast.
3409           if (shouldBroadcast(OpLane0, OpIdx, FirstLane) ||
3410               !canBeVectorized(OpILane0, OpIdx, FirstLane))
3411             ReorderingModes[OpIdx] = ReorderingMode::Splat;
3412           else if (isa<LoadInst>(OpILane0))
3413             ReorderingModes[OpIdx] = ReorderingMode::Load;
3414           else
3415             ReorderingModes[OpIdx] = ReorderingMode::Opcode;
3416         } else if (isa<Constant>(OpLane0)) {
3417           ReorderingModes[OpIdx] = ReorderingMode::Constant;
3418         } else if (isa<Argument>(OpLane0)) {
3419           // Our best hope is a Splat. It may save some cost in some cases.
3420           ReorderingModes[OpIdx] = ReorderingMode::Splat;
3421         } else {
3422           llvm_unreachable("Unexpected value kind.");
3423         }
3424       }
3425 
3426       // Check that we don't have same operands. No need to reorder if operands
3427       // are just perfect diamond or shuffled diamond match. Do not do it only
3428       // for possible broadcasts or non-power of 2 number of scalars (just for
3429       // now).
3430       auto &&SkipReordering = [this]() {
3431         SmallPtrSet<Value *, 4> UniqueValues;
3432         ArrayRef<OperandData> Op0 = OpsVec.front();
3433         for (const OperandData &Data : Op0)
3434           UniqueValues.insert(Data.V);
3435         for (ArrayRef<OperandData> Op :
3436              ArrayRef(OpsVec).slice(1, getNumOperands() - 1)) {
3437           if (any_of(Op, [&UniqueValues](const OperandData &Data) {
3438                 return !UniqueValues.contains(Data.V);
3439               }))
3440             return false;
3441         }
3442         // TODO: Check if we can remove a check for non-power-2 number of
3443         // scalars after full support of non-power-2 vectorization.
3444         return UniqueValues.size() != 2 &&
3445                hasFullVectorsOrPowerOf2(*R.TTI, Op0.front().V->getType(),
3446                                         UniqueValues.size());
3447       };
3448 
3449       // If the initial strategy fails for any of the operand indexes, then we
3450       // perform reordering again in a second pass. This helps avoid assigning
3451       // high priority to the failed strategy, and should improve reordering for
3452       // the non-failed operand indexes.
3453       for (int Pass = 0; Pass != 2; ++Pass) {
3454         // Check if no need to reorder operands since they're are perfect or
3455         // shuffled diamond match.
3456         // Need to do it to avoid extra external use cost counting for
3457         // shuffled matches, which may cause regressions.
3458         if (SkipReordering())
3459           break;
3460         // Skip the second pass if the first pass did not fail.
3461         bool StrategyFailed = false;
3462         // Mark all operand data as free to use.
3463         clearUsed();
3464         // We keep the original operand order for the FirstLane, so reorder the
3465         // rest of the lanes. We are visiting the nodes in a circular fashion,
3466         // using FirstLane as the center point and increasing the radius
3467         // distance.
3468         SmallVector<SmallVector<Value *, 2>> MainAltOps(NumOperands);
3469         for (unsigned I = 0; I < NumOperands; ++I)
3470           MainAltOps[I].push_back(getData(I, FirstLane).V);
3471 
3472         SmallBitVector UsedLanes(NumLanes);
3473         UsedLanes.set(FirstLane);
3474         for (unsigned Distance = 1; Distance != NumLanes; ++Distance) {
3475           // Visit the lane on the right and then the lane on the left.
3476           for (int Direction : {+1, -1}) {
3477             int Lane = FirstLane + Direction * Distance;
3478             if (Lane < 0 || Lane >= (int)NumLanes)
3479               continue;
3480             UsedLanes.set(Lane);
3481             int LastLane = Lane - Direction;
3482             assert(LastLane >= 0 && LastLane < (int)NumLanes &&
3483                    "Out of bounds");
3484             // Look for a good match for each operand.
3485             for (unsigned OpIdx = 0; OpIdx != NumOperands; ++OpIdx) {
3486               // Search for the operand that matches SortedOps[OpIdx][Lane-1].
3487               std::optional<unsigned> BestIdx =
3488                   getBestOperand(OpIdx, Lane, LastLane, ReorderingModes,
3489                                  MainAltOps[OpIdx], UsedLanes);
3490               // By not selecting a value, we allow the operands that follow to
3491               // select a better matching value. We will get a non-null value in
3492               // the next run of getBestOperand().
3493               if (BestIdx) {
3494                 // Swap the current operand with the one returned by
3495                 // getBestOperand().
3496                 swap(OpIdx, *BestIdx, Lane);
3497               } else {
3498                 // Enable the second pass.
3499                 StrategyFailed = true;
3500               }
3501               // Try to get the alternate opcode and follow it during analysis.
3502               if (MainAltOps[OpIdx].size() != 2) {
3503                 OperandData &AltOp = getData(OpIdx, Lane);
3504                 InstructionsState OpS =
3505                     getSameOpcode({MainAltOps[OpIdx].front(), AltOp.V}, TLI);
3506                 if (OpS && OpS.isAltShuffle())
3507                   MainAltOps[OpIdx].push_back(AltOp.V);
3508               }
3509             }
3510           }
3511         }
3512         // Skip second pass if the strategy did not fail.
3513         if (!StrategyFailed)
3514           break;
3515       }
3516     }
